# 🏃 Subway Surfer 3D — Complete Game in HTML5 Canvas

Here's a complete, playable Subway Surfer-style game in a **single HTML file** — just paste it into VS Code and open in your browser!

```
subway-surfer/
├── index.html          ← THE GAME (everything in one file)
└── README.md
```

---

## `index.html`

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Subway Surfer 3D</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            background: linear-gradient(135deg, #0f0c29, #302b63, #24243e);
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            overflow: hidden;
            user-select: none;
        }

        #gameContainer {
            position: relative;
            width: 400px;
            height: 600px;
            border-radius: 16px;
            overflow: hidden;
            box-shadow: 0 0 40px rgba(0, 150, 255, 0.3), 0 0 80px rgba(0, 100, 255, 0.1);
        }

        #gameCanvas {
            display: block;
            width: 100%;
            height: 100%;
        }

        #ui {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            padding: 15px 20px;
            display: flex;
            justify-content: space-between;
            align-items: flex-start;
            pointer-events: none;
            z-index: 10;
        }

        .ui-panel {
            background: rgba(0, 0, 0, 0.6);
            backdrop-filter: blur(10px);
            border: 1px solid rgba(255, 255, 255, 0.1);
            border-radius: 12px;
            padding: 8px 16px;
            color: white;
        }

        #scorePanel {
            font-size: 18px;
            font-weight: 700;
        }

        #scorePanel span {
            color: #00ff88;
        }

        #coinPanel {
            font-size: 16px;
            font-weight: 600;
            display: flex;
            align-items: center;
            gap: 6px;
        }

        #coinPanel span {
            color: #ffd700;
        }

        #startScreen, #gameOverScreen {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            background: rgba(0, 0, 0, 0.85);
            backdrop-filter: blur(8px);
            z-index: 20;
            color: white;
            text-align: center;
        }

        #gameOverScreen {
            display: none;
        }

        #startScreen h1, #gameOverScreen h1 {
            font-size: 42px;
            font-weight: 900;
            margin-bottom: 10px;
            background: linear-gradient(135deg, #00d2ff, #3a7bd5, #ff6b6b);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
            background-clip: text;
        }

        #startScreen p, #gameOverScreen p {
            font-size: 14px;
            color: #aaa;
            margin-bottom: 30px;
            line-height: 1.6;
        }

        .btn {
            padding: 14px 48px;
            font-size: 20px;
            font-weight: 700;
            border: none;
            border-radius: 50px;
            cursor: pointer;
            background: linear-gradient(135deg, #00d2ff, #3a7bd5);
            color: white;
            transition: transform 0.2s, box-shadow 0.2s;
            pointer-events: auto;
            letter-spacing: 1px;
        }

        .btn:hover {
            transform: scale(1.05);
            box-shadow: 0 0 30px rgba(0, 210, 255, 0.5);
        }

        .btn:active {
            transform: scale(0.98);
        }

        #finalScore {
            font-size: 36px;
            font-weight: 800;
            color: #00ff88;
            margin: 10px 0;
        }

        #finalCoins {
            font-size: 24px;
            font-weight: 700;
            color: #ffd700;
            margin-bottom: 20px;
        }

        .controls-info {
            margin-top: 20px;
            font-size: 12px;
            color: #666;
        }

        .controls-info kbd {
            background: rgba(255, 255, 255, 0.1);
            border: 1px solid rgba(255, 255, 255, 0.2);
            border-radius: 4px;
            padding: 2px 8px;
            font-size: 11px;
            margin: 0 2px;
        }

        #speedIndicator {
            position: absolute;
            bottom: 15px;
            left: 50%;
            transform: translateX(-50%);
            color: rgba(255, 255, 255, 0.3);
            font-size: 11px;
            z-index: 10;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="gameContainer">
        <canvas id="gameCanvas" width="400" height="600"></canvas>

        <div id="ui">
            <div class="ui-panel" id="scorePanel">🏃 Score: <span id="score">0</span></div>
            <div class="ui-panel" id="coinPanel">🪙 <span id="coins">0</span></div>
        </div>

        <div id="speedIndicator">Speed: <span id="speedValue">1.0</span>x</div>

        <div id="startScreen">
            <h1>🏃 SUBWAY<br>SURFER 3D</h1>
            <p>Dodge trains, collect coins!<br>Swipe or use arrow keys to move!</p>
            <button class="btn" id="startBtn">▶ PLAY</button>
            <div class="controls-info">
                <kbd>←</kbd> <kbd>→</kbd> Move Left/Right &nbsp;
                <kbd>↑</kbd> <kbd>↓</kbd> Jump/Slide<br>
                Or swipe on mobile!
            </div>
        </div>

        <div id="gameOverScreen">
            <h1>💥 GAME OVER</h1>
            <div id="finalScore">0</div>
            <div id="finalCoins">🪙 0</div>
            <button class="btn" id="restartBtn">🔄 PLAY AGAIN</button>
        </div>
    </div>

    <script>
        // ============================================
        // SUBWAY SURFER 3D — Complete Game Engine
        // ============================================

        (function () {
            "use strict";

            // --- Canvas Setup ---
            const canvas = document.getElementById("gameCanvas");
            const ctx = canvas.getContext("2d");
            const W = canvas.width;
            const H = canvas.height;

            // --- DOM Elements ---
            const scoreEl = document.getElementById("score");
            const coinsEl = document.getElementById("coins");
            const speedValueEl = document.getElementById("speedValue");
            const startScreen = document.getElementById("startScreen");
            const gameOverScreen = document.getElementById("gameOverScreen");
            const finalScoreEl = document.getElementById("finalScore");
            const finalCoinsEl = document.getElementById("finalCoins");
            const startBtn = document.getElementById("startBtn");
            const restartBtn = document.getElementById("restartBtn");

            // ============================================
            // GAME CONSTANTS
            // ============================================
            const LANE_COUNT = 3;
            const LANE_WIDTH = 90;
            const TRACK_WIDTH = LANE_WIDTH * LANE_COUNT + 20;
            const TRACK_LEFT = (W - TRACK_WIDTH) / 2;
            const HORIZON_Y = 180;
            const GROUND_Y = H - 40;
            const PLAYER_WIDTH = 40;
            const PLAYER_HEIGHT = 60;
            const OBSTACLE_HEIGHT = 50;
            const COIN_SIZE = 20;
            const BASE_SPEED = 4;
            const MAX_SPEED = 12;
            const SPEED_INCREMENT = 0.001;
            const JUMP_VELOCITY = -14;
            const GRAVITY = 0.6;
            const SLIDE_DURATION = 30;

            // --- Colors ---
            const COLORS = {
                sky: ["#1a1a2e", "#16213e", "#0f3460"],
                track: "#4a4a4a",
                trackLine: "#6a6a6a",
                rail: "#888888",
                trainBody: ["#e74c3c", "#3498db", "#2ecc71", "#f39c12", "#9b59b6"],
                trainStripe: "rgba(255,255,255,0.3)",
                coin: "#ffd700",
                coinShine: "#fff8dc",
                player: "#ff6b6b",
                playerOutline: "#cc3333",
                barrier: "#ff4444",
                barrierStripe: "#ffcc00",
            };

            // ============================================
            // GAME STATE
            // ============================================
            let gameState = "MENU";
            let score = 0;
            let coins = 0;
            let speed = BASE_SPEED;
            let distance = 0;
            let spawnTimer = 0;
            let coinSpawnTimer = 0;
            let screenShake = 0;
            let particles = [];

            // ============================================
            // PLAYER CLASS
            // ============================================
            class Player {
                constructor() {
                    this.lane = 1;
                    this.targetLane = 1;
                    this.visualX = this.getLaneX(1);
                    this.y = GROUND_Y - PLAYER_HEIGHT;
                    this.baseY = this.y;
                    this.velocityY = 0;
                    this.isJumping = false;
                    this.isSliding = false;
                    this.slideTimer = 0;
                    this.animFrame = 0;
                    this.animTimer = 0;
                }

                getLaneX(lane) {
                    return TRACK_LEFT + 10 + lane * LANE_WIDTH + LANE_WIDTH / 2;
                }

                moveLeft() {
                    if (this.targetLane > 0) {
                        this.targetLane--;
                    }
                }

                moveRight() {
                    if (this.targetLane < LANE_COUNT - 1) {
                        this.targetLane++;
                    }
                }

                jump() {
                    if (!this.isJumping && !this.isSliding) {
                        this.isJumping = true;
                        this.velocityY = JUMP_VELOCITY;
                    }
                }

                slide() {
                    if (!this.isJumping && !this.isSliding) {
                        this.isSliding = true;
                        this.slideTimer = SLIDE_DURATION;
                    }
                }

                update(dt) {
                    const targetX = this.getLaneX(this.targetLane);
                    const dx = targetX - this.visualX;
                    this.visualX += dx * 0.2;

                    if (this.isJumping) {
                        this.velocityY += GRAVITY * dt;
                        this.y += this.velocityY * dt;
                        if (this.y >= this.baseY) {
                            this.y = this.baseY;
                            this.isJumping = false;
                            this.velocityY = 0;
                        }
                    }

                    if (this.isSliding) {
                        this.slideTimer -= dt;
                        if (this.slideTimer <= 0) {
                            this.isSliding = false;
                        }
                    }

                    this.animTimer += dt;
                    if (this.animTimer > 5) {
                        this.animTimer = 0;
                        this.animFrame = (this.animFrame + 1) % 4;
                    }
                }

                getBounds() {
                    const h = this.isSliding ? PLAYER_HEIGHT * 0.5 : PLAYER_HEIGHT;
                    const y = this.isSliding ? this.y + PLAYER_HEIGHT * 0.5 : this.y;
                    return {
                        x: this.visualX - PLAYER_WIDTH / 2 + 5,
                        y: y + 5,
                        w: PLAYER_WIDTH - 10,
                        h: h - 10,
                    };
                }

                draw(ctx) {
                    const h = this.isSliding ? PLAYER_HEIGHT * 0.5 : PLAYER_HEIGHT;
                    const y = this.isSliding ? this.y + PLAYER_HEIGHT * 0.5 : this.y;
                    const x = this.visualX - PLAYER_WIDTH / 2;

                    ctx.save();

                    // Shadow
                    ctx.fillStyle = "rgba(0,0,0,0.3)";
                    ctx.beginPath();
                    ctx.ellipse(this.visualX, GROUND_Y + 5, 20, 6, 0, 0, Math.PI * 2);
                    ctx.fill();

                    // Body
                    const bodyGrad = ctx.createLinearGradient(x, y, x, y + h);
                    bodyGrad.addColorStop(0, "#ff8a8a");
                    bodyGrad.addColorStop(1, "#cc3333");
                    ctx.fillStyle = bodyGrad;

                    if (this.isSliding) {
                        // Slide pose
                        ctx.beginPath();
                        ctx.roundRect(x - 5, y, PLAYER_WIDTH + 10, h, 8);
                        ctx.fill();

                        // Head
                        ctx.fillStyle = "#ffcc99";
                        ctx.beginPath();
                        ctx.arc(x + PLAYER_WIDTH + 2, y + 12, 10, 0, Math.PI * 2);
                        ctx.fill();
                    } else {
                        // Running body
                        const bobY = this.isJumping ? 0 : Math.sin(this.animFrame * Math.PI / 2) * 3;

                        // Legs
                        ctx.fillStyle = "#334";
                        const legPhase = Math.sin(this.animFrame * Math.PI / 2);
                        ctx.fillRect(x + 8, y + h - 15 + bobY, 8, 15);
                        ctx.fillRect(x + PLAYER_WIDTH - 16, y + h - 15 - legPhase * 5 + bobY, 8, 15);

                        // Body
                        ctx.beginPath();
                        ctx.roundRect(x, y + 10 + bobY, PLAYER_WIDTH, h - 25, 6);
                        ctx.fill();

                        // Arms
                        ctx.strokeStyle = "#ffcc99";
                        ctx.lineWidth = 4;
                        ctx.lineCap = "round";
                        const armPhase = Math.sin(this.animFrame * Math.PI / 2);
                        ctx.beginPath();
                        ctx.moveTo(x + 5, y + 25 + bobY);
                        ctx.lineTo(x - 5, y + 35 + armPhase * 8 + bobY);
                        ctx.stroke();
                        ctx.beginPath();
                        ctx.moveTo(x + PLAYER_WIDTH - 5, y + 25 + bobY);
                        ctx.lineTo(x + PLAYER_WIDTH + 5, y + 35 - armPhase * 8 + bobY);
                        ctx.stroke();

                        // Head
                        ctx.fillStyle = "#ffcc99";
                        ctx.beginPath();
                        ctx.arc(this.visualX, y + 12 + bobY, 12, 0, Math.PI * 2);
                        ctx.fill();

                        // Hair
                        ctx.fillStyle = "#4a2800";
                        ctx.beginPath();
                        ctx.arc(this.visualX, y + 6 + bobY, 12, Math.PI, Math.PI * 2);
                        ctx.fill();

                        // Eyes
                        ctx.fillStyle = "#333";
                        ctx.beginPath();
                        ctx.arc(this.visualX - 4, y + 12 + bobY, 2, 0, Math.PI * 2);
                        ctx.arc(this.visualX + 4, y + 12 + bobY, 2, 0, Math.PI * 2);
                        ctx.fill();

                        // Smile
                        ctx.strokeStyle = "#333";
                        ctx.lineWidth = 1.5;
                        ctx.beginPath();
                        ctx.arc(this.visualX, y + 14 + bobY, 4, 0.1 * Math.PI, 0.9 * Math.PI);
                        ctx.stroke();
                    }

                    ctx.restore();
                }
            }

            // ============================================
            // OBSTACLE CLASS
            // ============================================
            class Obstacle {
                constructor(lane, z, type) {
                    this.lane = lane;
                    this.z = z;
                    this.type = type;
                    this.color = COLORS.trainBody[Math.floor(Math.random() * COLORS.trainBody.length)];
                    this.passed = false;
                }

                getScreenPos() {
                    const scale = 300 / (this.z + 300);
                    const screenX = W / 2 + (this.getLaneCenter() - W / 2) * scale;
                    const screenY = HORIZON_Y + (GROUND_Y - HORIZON_Y) * scale;
                    const screenW = LANE_WIDTH * 0.85 * scale;
                    const screenH = (this.type === "tall" ? OBSTACLE_HEIGHT * 1.8 : OBSTACLE_HEIGHT) * scale;
                    return { x: screenX, y: screenY, w: screenW, h: screenH, scale };
                }

                getLaneCenter() {
                    return TRACK_LEFT + 10 + this.lane * LANE_WIDTH + LANE_WIDTH / 2;
                }

                update(dt) {
                    this.z -= speed * dt * 60;
                }

                isAlive() {
                    return this.z > -50;
                }

                getBounds() {
                    const pos = this.getScreenPos();
                    return {
                        x: pos.x - pos.w / 2 + 4,
                        y: pos.y - pos.h + 4,
                        w: pos.w - 8,
                        h: pos.h - 8,
                    };
                }

                draw(ctx) {
                    const pos = this.getScreenPos();
                    if (pos.scale < 0.05) return;

                    const x = pos.x - pos.w / 2;
                    const y = pos.y - pos.h;
                    const w = pos.w;
                    const h = pos.h;

                    ctx.save();

                    // Shadow
                    ctx.fillStyle = "rgba(0,0,0,0.2)";
                    ctx.beginPath();
                    ctx.ellipse(pos.x, pos.y + 3, w * 0.4, 4 * pos.scale, 0, 0, Math.PI * 2);
                    ctx.fill();

                    // 3D effect — side
                    ctx.fillStyle = this.darkenColor(this.color, 0.6);
                    ctx.beginPath();
                    ctx.moveTo(x + w, y);
                    ctx.lineTo(x + w + 6 * pos.scale, y - 6 * pos.scale);
                    ctx.lineTo(x + w + 6 * pos.scale, y + h - 6 * pos.scale);
                    ctx.lineTo(x + w, y + h);
                    ctx.closePath();
                    ctx.fill();

                    // 3D effect — top
                    ctx.fillStyle = this.lightenColor(this.color, 1.2);
                    ctx.beginPath();
                    ctx.moveTo(x, y);
                    ctx.lineTo(x + 6 * pos.scale, y - 6 * pos.scale);
                    ctx.lineTo(x + w + 6 * pos.scale, y - 6 * pos.scale);
                    ctx.lineTo(x + w, y);
                    ctx.closePath();
                    ctx.fill();

                    // Main body
                    const bodyGrad = ctx.createLinearGradient(x, y, x, y + h);
                    bodyGrad.addColorStop(0, this.lightenColor(this.color, 1.1));
                    bodyGrad.addColorStop(0.5, this.color);
                    bodyGrad.addColorStop(1, this.darkenColor(this.color, 0.7));
                    ctx.fillStyle = bodyGrad;

                    ctx.beginPath();
                    ctx.roundRect(x, y, w, h, 4 * pos.scale);
                    ctx.fill();

                    // Stripe
                    ctx.fillStyle = "rgba(255,255,255,0.25)";
                    ctx.fillRect(x + w * 0.1, y + h * 0.3, w * 0.8, h * 0.08);

                    // Warning stripes (for barriers)
                    if (this.type === "barrier") {
                        const stripeH = h * 0.15;
                        ctx.fillStyle = "#ffcc00";
                        for (let sy = y + h * 0.1; sy < y + h * 0.5; sy += stripeH * 2) {
                            ctx.fillRect(x + 2, sy, w - 4, stripeH);
                        }
                    }

                    // Windows
                    if (this.type !== "barrier" && pos.scale > 0.15) {
                        ctx.fillStyle = "rgba(150,220,255,0.7)";
                        const winW = w * 0.15;
                        const winH = h * 0.2;
                        const winY = y + h * 0.15;
                        ctx.fillRect(x + w * 0.15, winY, winW, winH);
                        ctx.fillRect(x + w * 0.4, winY, winW, winH);
                        ctx.fillRect(x + w * 0.65, winY, winW, winH);
                    }

                    // Outline
                    ctx.strokeStyle = "rgba(0,0,0,0.3)";
                    ctx.lineWidth = 1;
                    ctx.beginPath();
                    ctx.roundRect(x, y, w, h, 4 * pos.scale);
                    ctx.stroke();

                    ctx.restore();
                }

                darkenColor(hex, factor) {
                    const r = parseInt(hex.slice(1, 3), 16);
                    const g = parseInt(hex.slice(3, 5), 16);
                    const b = parseInt(hex.slice(5, 7), 16);
                    return `rgb(${Math.floor(r * factor)},${Math.floor(g * factor)},${Math.floor(b * factor)})`;
                }

                lightenColor(hex, factor) {
                    const r = Math.min(255, parseInt(hex.slice(1, 3), 16) * factor);
                    const g = Math.min(255, parseInt(hex.slice(3, 5), 16) * factor);
                    const b = Math.min(255, parseInt(hex.slice(5, 7), 16) * factor);
                    return `rgb(${Math.floor(r)},${Math.floor(g)},${Math.floor(b)})`;
                }
            }

            // ============================================
            // COIN CLASS
            // ============================================
            class Coin {
                constructor(lane, z, height) {
                    this.lane = lane;
                    this.z = z;
                    this.height = height;
                    this.collected = false;
                    this.animAngle = Math.random() * Math.PI * 2;
                }

                getScreenPos() {
                    const scale = 300 / (this.z + 300);
                    const laneCenter = TRACK_LEFT + 10 + this.lane * LANE_WIDTH + LANE_WIDTH / 2;
                    const screenX = W / 2 + (laneCenter - W / 2) * scale;
                    const screenY = HORIZON_Y + (GROUND_Y - HORIZON_Y) * scale;
                    const baseY = screenY - this.height * 40 * scale;
                    const size = COIN_SIZE * scale;
                    return { x: screenX, y: baseY, size, scale };
                }

                update(dt) {
                    this.z -= speed * dt * 60;
                    this.animAngle += 3 * dt;
                }

                isAlive() {
                    return this.z > -50 && !this.collected;
                }

                getBounds() {
                    const pos = this.getScreenPos();
                    return {
                        x: pos.x - pos.size / 2,
                        y: pos.y - pos.size / 2,
                        w: pos.size,
                        h: pos.size,
                    };
                }

                draw(ctx) {
                    const pos = this.getScreenPos();
                    if (pos.scale < 0.05) return;

                    const squeeze = Math.abs(Math.cos(this.animAngle));
                    const rx = pos.size / 2 * Math.max(0.2, squeeze);
                    const ry = pos.size / 2;

                    ctx.save();
                    ctx.translate(pos.x, pos.y);

                    // Glow
                    ctx.shadowColor = "#ffd700";
                    ctx.shadowBlur = 10 * pos.scale;

                    // Coin body
                    const coinGrad = ctx.createRadialGradient(-rx * 0.3, -ry * 0.3, 0, 0, 0, rx);
                    coinGrad.addColorStop(0, "#fff8dc");
                    coinGrad.addColorStop(0.5, "#ffd700");
                    coinGrad.addColorStop(1, "#daa520");
                    ctx.fillStyle = coinGrad;

                    ctx.beginPath();
                    ctx.ellipse(0, 0, rx, ry, 0, 0, Math.PI * 2);
                    ctx.fill();

                    // Dollar sign
                    if (squeeze > 0.5) {
                        ctx.fillStyle = "#b8860b";
                        ctx.font = `bold ${Math.floor(pos.size * 0.7)}px Arial`;
                        ctx.textAlign = "center";
                        ctx.textBaseline = "middle";
                        ctx.fillText("$", 0, 1);
                    }

                    ctx.shadowBlur = 0;
                    ctx.restore();
                }
            }

            // ============================================
            // PARTICLE CLASS
            // ============================================
            class Particle {
                constructor(x, y, color) {
                    this.x = x;
                    this.y = y;
                    this.vx = (Math.random() - 0.5) * 8;
                    this.vy = (Math.random() - 1) * 6;
                    this.life = 1;
                    this.decay = 0.02 + Math.random() * 0.03;
                    this.size = 3 + Math.random() * 5;
                    this.color = color;
                }

                update(dt) {
                    this.x += this.vx * dt;
                    this.y += this.vy * dt;
                    this.vy += 0.2 * dt;
                    this.life -= this.decay * dt;
                }

                draw(ctx) {
                    ctx.save();
                    ctx.globalAlpha = Math.max(0, this.life);
                    ctx.fillStyle = this.color;
                    ctx.beginPath();
                    ctx.arc(this.x, this.y, this.size * this.life, 0, Math.PI * 2);
                    ctx.fill();
                    ctx.restore();
                }
            }

            // ============================================
            // GAME ENGINE
            // ============================================
            let player;
            let obstacles = [];
            let coinList = [];

            function createExplosion(x, y, color, count) {
                for (let i = 0; i < count; i++) {
                    particles.push(new Particle(x, y, color));
                }
            }

            function resetGame() {
                player = new Player();
                obstacles = [];
                coinList = [];
                particles = [];
                score = 0;
                coins = 0;
                speed = BASE_SPEED;
                distance = 0;
                spawnTimer = 0;
                coinSpawnTimer = 0;
                screenShake = 0;
            }

            function spawnObstacle() {
                const lane = Math.floor(Math.random() * LANE_COUNT);
                const types = ["train", "train", "train", "barrier", "tall"];
                const type = types[Math.floor(Math.random() * types.length)];

                for (const obs of obstacles) {
                    if (obs.lane === lane && obs.z < 400 && obs.z > 0) {
                        return;
                    }
                }

                obstacles.push(new Obstacle(lane, 1200, type));
            }

            function spawnCoin() {
                const lane = Math.floor(Math.random() * LANE_COUNT);
                const height = Math.random() > 0.7 ? (Math.random() > 0.5 ? 2 : 0) : 1;
                coinList.push(new Coin(lane, 1200, height));
            }

            function checkCollision(a, b) {
                return (
                    a.x < b.x + b.w &&
                    a.x + a.w > b.x &&
                    a.y < b.y + b.h &&
                    a.y + a.h > b.y
                );
            }

            function update(dt) {
                if (gameState !== "PLAYING") return;

                if (speed < MAX_SPEED) {
                    speed += SPEED_INCREMENT * dt;
                }

                distance += speed * dt;
                score = Math.floor(distance * 2);
                spawnTimer += dt;
                coinSpawnTimer += dt;

                const spawnRate = Math.max(20, 50 - speed * 2);
                if (spawnTimer > spawnRate) {
                    spawnTimer = 0;
                    spawnObstacle();
                }

                if (coinSpawnTimer > 15) {
                    coinSpawnTimer = 0;
                    if (Math.random() > 0.3) {
                        spawnCoin();
                    }
                }

                player.update(dt);

                for (let i = obstacles.length - 1; i >= 0; i--) {
                    obstacles[i].update(dt);
                    if (!obstacles[i].isAlive()) {
                        obstacles.splice(i, 1);
                        continue;
                    }
                    if (!obstacles[i].passed && obstacles[i].z < 60) {
                        obstacles[i].passed = true;
                    }
                }

                for (let i = coinList.length - 1; i >= 0; i--) {
                    coinList[i].update(dt);
                    if (!coinList[i].isAlive()) {
                        coinList[i].collected = true;
                        coinList.splice(i, 1);
                    }
                }

                const playerBounds = player.getBounds();

                for (const obs of obstacles) {
                    if (obs.z < 80 && obs.z > -30) {
                        const obsBounds = obs.getBounds();
                        if (checkCollision(playerBounds, obsBounds)) {
                            gameOver();
                            return;
                        }
                    }
                }

                for (const coin of coinList) {
                    if (coin.z < 100 && coin.z > -50) {
                        const coinBounds = coin.getBounds();
                        if (checkCollision(playerBounds, coinBounds)) {
                            coin.collected = true;
                            coins++;
                            score += 10;
                            createExplosion(coin.getScreenPos().x, coin.getScreenPos().y, "#ffd700", 12);
                        }
                    }
                }

                for (let i = particles.length - 1; i >= 0; i--) {
                    particles[i].update(dt);
                    if (particles[i].life <= 0) {
                        particles.splice(i, 1);
                    }
                }

                if (screenShake > 0) {
                    screenShake -= dt * 2;
                }

                scoreEl.textContent = score;
                coinsEl.textContent = coins;
                speedValueEl.textContent = (speed / BASE_SPEED).toFixed(1);
            }

            function gameOver() {
                gameState = "GAMEOVER";
                screenShake = 15;
                createExplosion(player.visualX, player.y + PLAYER_HEIGHT / 2, "#ff4444", 30);
                createExplosion(player.visualX, player.y + PLAYER_HEIGHT / 2, "#ffaa00", 20);

                finalScoreEl.textContent = score;
                finalCoinsEl.textContent = "🪙 " + coins;

                setTimeout(() => {
                    gameOverScreen.style.display = "flex";
                }, 500);
            }

            // ============================================
            // RENDERING
            // ============================================
            function drawBackground() {
                const skyGrad = ctx.createLinearGradient(0, 0, 0, HORIZON_Y + 50);
                skyGrad.addColorStop(0, "#0a0a2e");
                skyGrad.addColorStop(0.5, "#1a1a4e");
                skyGrad.addColorStop(1, "#2a2a5e");
                ctx.fillStyle = skyGrad;
                ctx.fillRect(0, 0, W, HORIZON_Y + 50);

                // Stars
                ctx.fillStyle = "rgba(255,255,255,0.6)";
                for (let i = 0; i < 30; i++) {
                    const sx = (i * 137.5 + distance * 0.05) % W;
                    const sy = (i * 73.3) % (HORIZON_Y - 20);
                    const ss = 1 + (i % 3);
                    ctx.beginPath();
                    ctx.arc(sx, sy, ss, 0, Math.PI * 2);
                    ctx.fill();
                }

                // City skyline
                ctx.fillStyle = "#1a1a3e";
                for (let i = 0; i < 8; i++) {
                    const bx = i * 60 - (distance * 0.1) % 60;
                    const bh = 30 + (i * 47) % 50;
                    ctx.fillRect(bx, HORIZON_Y - bh + 20, 40, bh + 20);

                    ctx.fillStyle = "rgba(255,200,50,0.3)";
                    for (let wy = 0; wy < bh - 10; wy += 12) {
                        for (let wx = 5; wx < 35; wx += 10) {
                            if (Math.random() > 0.4) {
                                ctx.fillRect(bx + wx, HORIZON_Y - bh + 25 + wy, 4, 6);
                            }
                        }
                    }
                    ctx.fillStyle = "#1a1a3e";
                }

                // Ground
                const groundGrad = ctx.createLinearGradient(0, HORIZON_Y, 0, H);
                groundGrad.addColorStop(0, "#3a3a3a");
                groundGrad.addColorStop(1, "#2a2a2a");
                ctx.fillStyle = groundGrad;

                ctx.beginPath();
                ctx.moveTo(0, HORIZON_Y + 30);
                ctx.lineTo(W, HORIZON_Y + 30);
                ctx.lineTo(W, H);
                ctx.lineTo(0, H);
                ctx.closePath();
                ctx.fill();
            }

            function drawTrack() {
                ctx.save();

                // Track surface with perspective
                const trackGrad = ctx.createLinearGradient(0, HORIZON_Y + 30, 0, GROUND_Y);
                trackGrad.addColorStop(0, "#555");
                trackGrad.addColorStop(1, "#444");
                ctx.fillStyle = trackGrad;

                // Draw track in perspective
                const trackTop = HORIZON_Y + 30;
                const vanishingX = W / 2;

                ctx.beginPath();
                ctx.moveTo(vanishingX - 5, trackTop);
                ctx.lineTo(vanishingX + 5, trackTop);
                ctx.lineTo(TRACK_LEFT + TRACK_WIDTH, GROUND_Y);
                ctx.lineTo(TRACK_LEFT, GROUND_Y);
                ctx.closePath();
                ctx.fill();

                // Track edges
                ctx.strokeStyle = "#ffcc00";
                ctx.lineWidth = 2;
                ctx.setLineDash([10, 15]);

                // Left edge
                ctx.beginPath();
                ctx.moveTo(vanishingX - 5, trackTop);
                ctx.lineTo(TRACK_LEFT, GROUND_Y);
                ctx.stroke();

                // Right edge
                ctx.beginPath();
                ctx.moveTo(vanishingX + 5, trackTop);
                ctx.lineTo(TRACK_LEFT + TRACK_WIDTH, GROUND_Y);
                ctx.stroke();

                ctx.setLineDash([]);

                // Lane dividers
                for (let lane = 1; lane < LANE_COUNT; lane++) {
                    const topX = vanishingX + (TRACK_LEFT + 10 + lane * LANE_WIDTH - vanishingX) * 0.02;
                    const bottomX = TRACK_LEFT + 10 + lane * LANE_WIDTH;

                    ctx.strokeStyle = "rgba(255,255,255,0.3)";
                    ctx.lineWidth = 1;
                    ctx.setLineDash([8, 12]);

                    ctx.beginPath();
                    ctx.moveTo(topX, trackTop + 5);
                    ctx.lineTo(bottomX, GROUND_Y);
                    ctx.stroke();

                    ctx.setLineDash([]);
                }

                // Horizontal track lines (sleepers)
                for (let i = 0; i < 20; i++) {
                    const t = ((i * 0.05 + distance * 0.01) % 1);
                    const y = trackTop + (GROUND_Y - trackTop) * t;
                    const perspectiveScale = t;
                    const leftX = vanishingX + (TRACK_LEFT - vanishingX) * perspectiveScale;
                    const rightX = vanishingX + (TRACK_LEFT + TRACK_WIDTH - vanishingX) * perspectiveScale;

                    ctx.strokeStyle = `rgba(100,80,60,${0.4 * perspectiveScale})`;
                    ctx.lineWidth = 2 * perspectiveScale + 0.5;
                    ctx.beginPath();
                    ctx.moveTo(leftX, y);
                    ctx.lineTo(rightX, y);
                    ctx.stroke();
                }

                // Rails
                for (let lane = 0; lane <= LANE_COUNT; lane++) {
                    const topX = vanishingX + (TRACK_LEFT + 10 + lane * LANE_WIDTH + LANE_WIDTH / 2 - 2 - vanishingX) * 0.02;
                    const bottomX = TRACK_LEFT + 10 + lane * LANE_WIDTH + LANE_WIDTH / 2 - 2;

                    ctx.strokeStyle = "#aaa";
                    ctx.lineWidth = 2;
                    ctx.beginPath();
                    ctx.moveTo(topX, trackTop + 3);
                    ctx.lineTo(bottomX, GROUND_Y);
                    ctx.stroke();
                }

                ctx.restore();
            }

            function render() {
                ctx.save();

                if (screenShake > 0) {
                    ctx.translate(
                        (Math.random() - 0.5) * screenShake,
                        (Math.random() - 0.5) * screenShake
                    );
                }

                ctx.clearRect(0, 0, W, H);

                drawBackground();
                drawTrack();

                const allEntities = [
                    ...obstacles.map((o) => ({ type: "obstacle", entity: o, z: o.z })),
                    ...coinList.map((c) => ({ type: "coin", entity: c, z: c.z })),
                ];

                allEntities.sort((a, b) => b.z - a.z);

                for (const item of allEntities) {
                    if (item.type === "obstacle") {
                        item.entity.draw(ctx);
                    } else {
                        item.entity.draw(ctx);
                    }
                }

                for (const particle of particles) {
                    particle.draw(ctx);
                }

                if (gameState === "PLAYING" || gameState === "GAMEOVER") {
                    player.draw(ctx);
                }

                ctx.restore();
            }

            // ============================================
            // GAME LOOP
            // ============================================
            let lastTime = 0;
            let accumulator = 0;
            const FIXED_DT = 1;

            function gameLoop(timestamp) {
                if (!lastTime) lastTime = timestamp;
                const frameTime = Math.min((timestamp - lastTime) / 16.67, 3);
                lastTime = timestamp;

                accumulator += frameTime;

                while (accumulator >= FIXED_DT) {
                    update(FIXED_DT);
                    accumulator -= FIXED_DT;
                }

                render();
                requestAnimationFrame(gameLoop);
            }

            // ============================================
            // INPUT HANDLING
            // ============================================
            function handleKeyDown(e) {
                if (gameState !== "PLAYING") return;

                switch (e.key) {
                    case "ArrowLeft":
                    case "a":
                    case "A":
                        player.moveLeft();
                        break;
                    case "ArrowRight":
                    case "d":
                    case "D":
                        player.moveRight();
                        break;
                    case "ArrowUp":
                    case "w":
                    case "W":
                    case " ":
                        player.jump();
                        e.preventDefault();
                        break;
                    case "ArrowDown":
                    case "s":
                    case "S":
                        player.slide();
                        break;
                }
            }

            let touchStartX = 0;
            let touchStartY = 0;

            function handleTouchStart(e) {
                e.preventDefault();
                touchStartX = e.touches[0].clientX;
                touchStartY = e.touches[0].clientY;
            }

            function handleTouchEnd(e) {
                e.preventDefault();
                if (gameState !== "PLAYING") return;

                const touchEndX = e.changedTouches[0].clientX;
                const touchEndY = e.changedTouches[0].clientY;
                const dx = touchEndX - touchStartX;
                const dy = touchEndY - touchStartY;
                const absDx = Math.abs(dx);
                const absDy = Math.abs(dy);

                const minSwipe = 30;

                if (absDx > absDy && absDx > minSwipe) {
                    if (dx > 0) player.moveRight();
                    else player.moveLeft();
                } else if (absDy > minSwipe) {
                    if (dy < 0) player.jump();
                    else player.slide();
                }
            }

            // ============================================
            // EVENT LISTENERS
            // ============================================
            document.addEventListener("keydown", handleKeyDown);
            canvas.addEventListener("touchstart", handleTouchStart, { passive: false });
            canvas.addEventListener("touchend", handleTouchEnd, { passive: false });

            startBtn.addEventListener("click", () => {
                startScreen.style.display = "none";
                gameState = "PLAYING";
                resetGame();
            });

            restartBtn.addEventListener("click", () => {
                gameOverScreen.style.display = "none";
                gameState = "PLAYING";
                resetGame();
            });

            // ============================================
            // START
            // ============================================
            resetGame();
            requestAnimationFrame(gameLoop);
        })();
    </script>
</body>
</html>
