    </div>

    <script>
        // ============================================
        // BLACK MYTH WUKONG — Complete Action RPG
        // ============================================

        (function () {
            "use strict";

            // --- Canvas ---
            const canvas = document.getElementById("gameCanvas");
            const ctx = canvas.getContext("2d");
            const W = canvas.width;
            const H = canvas.height;

            // --- DOM ---
            const healthBar = document.getElementById("healthBar");
            const staminaBar = document.getElementById("staminaBar");
            const manaBar = document.getElementById("manaBar");
            const healthValue = document.getElementById("healthValue");
            const staminaValue = document.getElementById("staminaValue");
            const manaValue = document.getElementById("manaValue");
            const soulsDisplay = document.getElementById("soulsDisplay");
            const killsDisplay = document.getElementById("killsDisplay");
            const comboCountDisplay = document.getElementById("comboCount");
            const comboDisplay = document.getElementById("comboDisplay");
            const bossHealthContainer = document.getElementById("bossHealthContainer");
            const bossNameDisplay = document.getElementById("bossName");
            const bossHealthFill = document.getElementById("bossHealthFill");
            const startScreen = document.getElementById("startScreen");
            const gameOverScreen = document.getElementById("gameOverScreen");
            const victoryScreen = document.getElementById("victoryScreen");
            const finalStats = document.getElementById("finalStats");
            const victoryStats = document.getElementById("victoryStats");
            const startBtn = document.getElementById("startBtn");
            const retryBtn = document.getElementById("retryBtn");
            const victoryBtn = document.getElementById("victoryBtn");

            // ============================================
            // CONSTANTS
            // ============================================
            const PLAYER_SPEED = 3.5;
            const SPRINT_MULTIPLIER = 1.8;
            const DODGE_SPEED = 12;
            const DODGE_DURATION = 15;
            const DODGE_COOLDOWN = 40;
            const STAMINA_REGEN = 0.4;
            const STAMINA_REGEN_DELAY = 30;
            const MANA_REGEN = 0.15;
            const GRAVITY = 0.5;
            const JUMP_FORCE = -10;
            const COMBO_WINDOW = 60;
            const MAX_COMBO = 10;

            // ============================================
            // PARTICLE SYSTEM
            // ============================================
            class Particle {
                constructor(x, y, vx, vy, life, color, size, type = "circle") {
                    this.x = x;
                    this.y = y;
                    this.vx = vx;
                    this.vy = vy;
                    this.life = life;
                    this.maxLife = life;
                    this.color = color;
                    this.size = size;
                    this.type = type;
                    this.rotation = Math.random() * Math.PI * 2;
                    this.rotationSpeed = (Math.random() - 0.5) * 0.2;
                }

                update(dt) {
                    this.x += this.vx * dt;
                    this.y += this.vy * dt;
                    this.vy += 0.05 * dt;
                    this.life -= dt;
                    this.rotation += this.rotationSpeed * dt;
                }

                draw(ctx) {
                    const alpha = Math.max(0, this.life / this.maxLife);
                    ctx.save();
                    ctx.globalAlpha = alpha;
                    ctx.translate(this.x, this.y);
                    ctx.rotate(this.rotation);

                    if (this.type === "spark") {
                        ctx.fillStyle = this.color;
                        ctx.beginPath();
                        ctx.moveTo(-this.size, 0);
                        ctx.lineTo(this.size, 0);
                        ctx.lineTo(this.size * 0.3, -this.size * 0.5);
                        ctx.lineTo(-this.size * 0.3, this.size * 0.5);
                        ctx.closePath();
                        ctx.fill();
                    } else if (this.type === "ring") {
                        ctx.strokeStyle = this.color;
                        ctx.lineWidth = 2;
                        ctx.beginPath();
                        ctx.arc(0, 0, this.size * (1 - alpha + 0.3), 0, Math.PI * 2);
                        ctx.stroke();
                    } else if (this.type === "slash") {
                        ctx.strokeStyle = this.color;
                        ctx.lineWidth = 3;
                        ctx.beginPath();
                        ctx.arc(0, 0, this.size * 2, -0.5, 0.5);
                        ctx.stroke();
                    } else {
                        ctx.fillStyle = this.color;
                        ctx.beginPath();
                        ctx.arc(0, 0, this.size * alpha, 0, Math.PI * 2);
                        ctx.fill();
                    }

                    ctx.restore();
                }
            }

            function spawnParticles(x, y, count, color, spread = 5, size = 4, type = "circle") {
                for (let i = 0; i < count; i++) {
                    particles.push(new Particle(
                        x + (Math.random() - 0.5) * 20,
                        y + (Math.random() - 0.5) * 20,
                        (Math.random() - 0.5) * spread,
                        (Math.random() - 0.5) * spread - 2,
                        20 + Math.random() * 30,
                        color,
                        size + Math.random() * 3,
                        type
                    ));
                }
            }

            function spawnSlash(x, y, direction) {
                for (let i = 0; i < 8; i++) {
                    particles.push(new Particle(
                        x + direction * (Math.random() - 0.5) * 30,
                        y + (Math.random() - 0.5) * 40,
                        direction * (2 + Math.random() * 4),
                        (Math.random() - 0.5) * 3,
                        15 + Math.random() * 15,
                        Math.random() > 0.5 ? "#ffd700" : "#ff6b00",
                        3 + Math.random() * 5,
                        "slash"
                    ));
                }
            }

            // ============================================
            // DAMAGE NUMBER
            // ============================================
            class DamageNumber {
                constructor(x, y, damage, type = "normal") {
                    this.x = x + (Math.random() - 0.5) * 30;
                    this.y = y;
                    this.damage = damage;
                    this.life = 60;
                    this.vy = -2;
                    this.type = type;
                }

                update(dt) {
                    this.y += this.vy * dt;
                    this.vy += 0.03 * dt;
                    this.life -= dt;
                }

                draw(ctx) {
                    const alpha = Math.max(0, this.life / 60);
                    ctx.save();
                    ctx.globalAlpha = alpha;
                    ctx.font = this.type === "crit" ? "bold 28px Arial" : this.type === "heavy" ? "bold 24px Arial" : "bold 18px Arial";
                    ctx.textAlign = "center";
                    ctx.fillStyle = this.type === "crit" ? "#ff0000" : this.type === "heavy" ? "#ff6b00" : this.type === "skill" ? "#00aaff" : "#ffffff";
                    ctx.strokeStyle = "rgba(0,0,0,0.8)";
                    ctx.lineWidth = 3;
                    ctx.strokeText(Math.floor(this.damage).toString(), this.x, this.y);
                    ctx.fillText(Math.floor(this.damage).toString(), this.x, this.y);
                    if (this.type === "crit") {
                        ctx.font = "bold 12px Arial";
                        ctx.fillText("CRIT!", this.x, this.y - 25);
                    }
                    ctx.restore();
                }
            }

            // ============================================
            // SKILL DEFINITIONS
            // ============================================
            const SKILLS = [
                {
                    name: "Cyclone Strike",
                    icon: "🌀",
                    key: "u",
                    cooldown: 180,
                    currentCooldown: 0,
                    manaCost: 25,
                    damage: 60,
                    range: 120,
                    color: "#4169e1",
                    execute: (player, enemies, particles) => {
                        spawnParticles(player.x, player.y - 40, 30, "#4169e1", 8, 5, "circle");
                        for (let i = 0; i < 12; i++) {
                            const angle = (i / 12) * Math.PI * 2;
                            particles.push(new Particle(
                                player.x + Math.cos(angle) * 50,
                                player.y - 40 + Math.sin(angle) * 50,
                                Math.cos(angle) * 3,
                                Math.sin(angle) * 3,
                                20,
                                "#6495ed",
                                4,
                                "circle"
                            ));
                        }
                        for (const enemy of enemies) {
                            const dist = Math.hypot(enemy.x - player.x, enemy.y - player.y);
                            if (dist < 150) {
                                enemy.takeDamage(60, player.facing);
                                enemy.knockback(player.facing * 8);
                            }
                        }
                    }
                },
                {
                    name: "Fire Barrage",
                    icon: "🔥",
                    key: "i",
                    cooldown: 240,
                    currentCooldown: 0,
                    manaCost: 35,
                    damage: 80,
                    range: 300,
                    color: "#ff4400",
                    execute: (player, enemies, particles) => {
                        for (let i = 0; i < 6; i++) {
                            setTimeout(() => {
                                const fireX = player.x + player.facing * 30;
                                const fireY = player.y - 40;
                                spawnParticles(fireX, fireY, 8, "#ff4400", 6, 5, "circle");
                                spawnParticles(fireX, fireY, 5, "#ffd700", 4, 3, "circle");

                                for (const enemy of enemies) {
                                    const dist = Math.hypot(enemy.x - fireX, (enemy.y - 30) - fireY);
                                    if (dist < 60) {
                                        enemy.takeDamage(15, player.facing);
                                    }
                                }
                            }, i * 80);
                        }
                        spawnParticles(player.x, player.y - 40, 20, "#ff6600", 5, 6, "circle");
                    }
                },
                {
                    name: "Thunder Clap",
                    icon: "⚡",
                    key: "o",
                    cooldown: 300,
                    currentCooldown: 0,
                    manaCost: 45,
                    damage: 120,
                    range: 200,
                    color: "#00ccff",
                    execute: (player, enemies, particles) => {
                        const thunderX = player.x + player.facing * 80;
                        const thunderY = player.y - 20;

                        for (let i = 0; i < 20; i++) {
                            particles.push(new Particle(
                                thunderX + (Math.random() - 0.5) * 60,
                                thunderY + (Math.random() - 0.5) * 60,
                                (Math.random() - 0.5) * 6,
                                (Math.random() - 0.5) * 6,
                                25 + Math.random() * 20,
                                Math.random() > 0.5 ? "#00ccff" : "#ffffff",
                                2 + Math.random() * 4,
                                "spark"
                            ));
                        }

                        for (let i = 0; i < 5; i++) {
                            setTimeout(() => {
                                particles.push(new Particle(
                                    thunderX, thunderY - 60, 0, 0, 10,
                                    "#00ccff", 40 + i * 10, "ring"
                                ));
                            }, i * 30);
                        }

                        for (const enemy of enemies) {
                            const dist = Math.hypot(enemy.x - thunderX, enemy.y - thunderY);
                            if (dist < 120) {
                                enemy.takeDamage(40, player.facing);
                                enemy.stunned = 40;
                            }
                        }
                    }
                }
            ];

            // ============================================
            // ENEMY CLASS
            // ============================================
            class Enemy {
                constructor(x, y, type = "minion") {
                    this.x = x;
                    this.y = y;
                    this.vx = 0;
                    this.vy = 0;
                    this.type = type;
                    this.facing = -1;
                    this.animFrame = 0;
                    this.animTimer = 0;
                    this.state = "idle";
                    this.stateTimer = 0;
                    this.attackCooldown = 0;
                    this.stunned = 0;
                    this.knockbackVx = 0;
                    this.flashTimer = 0;

                    if (type === "minion") {
                        this.maxHp = 80;
                        this.hp = 80;
                        this.damage = 12;
                        this.speed = 1.5;
                        this.attackRange = 50;
                        this.color = "#8b4513";
                        this.size = 35;
                        this.souls = 20;
                    } else if (type === "heavy") {
                        this.maxHp = 200;
                        this.hp = 200;
                        this.damage = 25;
                        this.speed = 0.8;
                        this.attackRange = 60;
                        this.color = "#4a0080";
                        this.size = 50;
                        this.souls = 50;
                    } else if (type === "boss") {
                        this.maxHp = 800;
                        this.hp = 800;
                        this.damage = 35;
                        this.speed = 1.2;
                        this.attackRange = 80;
                        this.color = "#cc0000";
                        this.size = 70;
                        this.souls = 500;
                        this.phase = 1;
                    }
                }

                takeDamage(amount, direction) {
                    this.hp -= amount;
                    this.flashTimer = 5;
                    this.knockbackVx = direction * 3;
                    spawnParticles(this.x, this.y - this.size, 6, "#ff4444", 4, 3);
                    damageNumbers.push(new DamageNumber(this.x, this.y - this.size, amount, amount > 30 ? "crit" : "normal"));
                }

                knockback(force) {
                    this.knockbackVx = force;
                }

                update(dt, playerX, playerY) {
                    if (this.stunned > 0) {
                        this.stunned -= dt;
                        this.knockbackVx *= 0.85;
                        this.x += this.knockbackVx * dt;
                        return;
                    }

                    this.knockbackVx *= 0.85;
                    this.x += this.knockbackVx * dt;

                    if (this.flashTimer > 0) this.flashTimer -= dt;
                    if (this.attackCooldown > 0) this.attackCooldown -= dt;

                    const dx = playerX - this.x;
                    const dist = Math.abs(dx);
                    this.facing = dx > 0 ? 1 : -1;

                    this.animTimer += dt;
                    if (this.animTimer > 8) {
                        this.animTimer = 0;
                        this.animFrame = (this.animFrame + 1) % 4;
                    }

                    this.stateTimer -= dt;

                    if (this.state === "idle" || this.state === "chase") {
                        if (dist > this.attackRange) {
                            this.state = "chase";
                            this.x += this.facing * this.speed * dt;
                        } else if (this.attackCooldown <= 0) {
                            this.state = "attack";
                            this.stateTimer = 30;
                            this.attackCooldown = this.type === "boss" ? 40 : 50;
                        }
                    } else if (this.state === "attack") {
                        if (this.stateTimer <= 0) {
                            this.state = "idle";
                        }
                    }

                    this.x = Math.max(50, Math.min(W - 50, this.x));
                }

                getAttackHitbox() {
                    return {
                        x: this.x + this.facing * 20 - 30,
                        y: this.y - this.size - 20,
                        w: 60,
                        h: this.size + 20,
                    };
                }

                draw(ctx) {
                    ctx.save();
                    ctx.translate(this.x, this.y);

                    const flash = this.flashTimer > 0 && Math.floor(this.flashTimer) % 2 === 0;

                    // Shadow
                    ctx.fillStyle = "rgba(0,0,0,0.3)";
                    ctx.beginPath();
                    ctx.ellipse(0, 5, this.size * 0.6, 8, 0, 0, Math.PI * 2);
                    ctx.fill();

                    const dir = this.facing;

                    if (this.type === "minion") {
                        // Body
                        ctx.fillStyle = flash ? "#ffffff" : this.color;
                        ctx.beginPath();
                        ctx.roundRect(-this.size / 2, -this.size, this.size, this.size, 6);
                        ctx.fill();

                        // Eyes
                        ctx.fillStyle = "#ff0000";
                        ctx.beginPath();
                        ctx.arc(dir * 8, -this.size * 0.7, 4, 0, Math.PI * 2);
                        ctx.arc(dir * 18, -this.size * 0.65, 3, 0, Math.PI * 2);
                        ctx.fill();

                        // Club
                        if (this.state === "attack") {
                            ctx.save();
                            ctx.translate(dir * 15, -this.size * 0.5);
                            ctx.rotate(dir * (-0.5 + this.stateTimer / 30 * 1.5));
                            ctx.fillStyle = "#666";
                            ctx.fillRect(-4, -30, 8, 40);
                            ctx.fillStyle = "#888";
                            ctx.beginPath();
                            ctx.arc(0, -30, 10, 0, Math.PI * 2);
                            ctx.fill();
                            ctx.restore();
                        }

                    } else if (this.type === "heavy") {
                        ctx.fillStyle = flash ? "#ffffff" : this.color;
                        ctx.beginPath();
                        ctx.roundRect(-this.size / 2, -this.size, this.size, this.size, 8);
                        ctx.fill();

                        ctx.fillStyle = "#ff00ff";
                        ctx.beginPath();
                        ctx.arc(dir * 10, -this.size * 0.7, 5, 0, Math.PI * 2);
                        ctx.arc(dir * 22, -this.size * 0.65, 4, 0, Math.PI * 2);
                        ctx.fill();

                        if (this.state === "attack") {
                            ctx.save();
                            ctx.translate(dir * 20, -this.size * 0.5);
                            ctx.rotate(dir * (-0.8 + this.stateTimer / 30 * 2));
                            ctx.fillStyle = "#666";
                            ctx.fillRect(-6, -40, 12, 55);
                            ctx.restore();
                        }

                    } else if (this.type === "boss") {
                        // Aura
                        ctx.globalAlpha = 0.15 + Math.sin(Date.now() / 300) * 0.05;
                        ctx.fillStyle = "#ff0000";
                        ctx.beginPath();
                        ctx.arc(0, -this.size / 2, this.size * 1.3, 0, Math.PI * 2);
                        ctx.fill();
                        ctx.globalAlpha = 1;

                        ctx.fillStyle = flash ? "#ffffff" : this.color;
                        ctx.beginPath();
                        ctx.roundRect(-this.size / 2, -this.size, this.size, this.size, 10);
                        ctx.fill();

                        // Crown
                        ctx.fillStyle = "#ffd700";
                        for (let i = -2; i <= 2; i++) {
                            ctx.beginPath();
                            ctx.moveTo(i * 12 - 6, -this.size);
                            ctx.lineTo(i * 12, -this.size - 18);
                            ctx.lineTo(i * 12 + 6, -this.size);
                            ctx.fill();
                        }

                        ctx.fillStyle = "#ffff00";
                        ctx.beginPath();
                        ctx.arc(dir * 15, -this.size * 0.7, 7, 0, Math.PI * 2);
                        ctx.arc(dir * 30, -this.size * 0.65, 5, 0, Math.PI * 2);
                        ctx.fill();

                        // Weapon
                        if (this.state === "attack") {
                            ctx.save();
                            ctx.translate(dir * 25, -this.size * 0.5);
                            ctx.rotate(dir * (-1 + this.stateTimer / 30 * 2.5));
                            ctx.fillStyle = "#ffd700";
                            ctx.fillRect(-5, -50, 10, 70);
                            ctx.fillStyle = "#ff4400";
                            ctx.beginPath();
                            ctx.moveTo(-15, -50);
                            ctx.lineTo(0, -75);
                            ctx.lineTo(15, -50);
                            ctx.fill();
                            ctx.restore();
                        }
                    }

                    // Health bar
                    if (this.hp < this.maxHp) {
                        const barW = this.size * 1.2;
                        const barH = 5;
                        const barY = -this.size - 15;
                        ctx.fillStyle = "#333";
                        ctx.fillRect(-barW / 2, barY, barW, barH);
                        ctx.fillStyle = this.hp > this.maxHp * 0.3 ? "#ff4444" : "#ff0000";
                        ctx.fillRect(-barW / 2, barY, barW * (this.hp / this.maxHp), barH);
                    }

                    ctx.restore();
                }
            }

            // ============================================
            // PLAYER CLASS (WUKONG)
            // ============================================
            class Player {
                constructor() {
                    this.x = 200;
                    this.y = H - 100;
                    this.vx = 0;
                    this.vy = 0;
                    this.facing = 1;
                    this.grounded = true;

                    // Stats
                    this.maxHp = 100;
                    this.hp = 100;
                    this.maxStamina = 100;
                    this.stamina = 100;
                    this.maxMana = 100;
                    this.mana = 100;

                    // State
                    this.state = "idle";
                    this.stateTimer = 0;
                    this.comboCount = 0;
                    this.comboTimer = 0;
                    this.dodgeTimer = 0;
                    this.dodgeCooldownTimer = 0;
                    this.staminaRegenTimer = 0;
                    this.iFrames = 0;
                    this.attackHitbox = null;

                    // Animation
                    this.animFrame = 0;
                    this.animTimer = 0;

                    // Stats
                    this.souls = 0;
                    this.kills = 0;
                }

                getAttackHitbox() {
                    if (this.attackHitbox) return this.attackHitbox;
                    const range = this.comboCount >= 3 ? 70 : 55;
                    return {
                        x: this.x + this.facing * 20 - 10,
                        y: this.y - 80,
                        w: range,
                        h: 60,
                    };
                }

                lightAttack() {
                    if (this.state !== "idle" && this.state !== "run" && this.state !== "combo") return;
                    if (this.stamina < 10) return;

                    this.stamina -= 10;
                    this.staminaRegenTimer = STAMINA_REGEN_DELAY;
                    this.state = "combo";
                    this.stateTimer = 18;
                    this.comboCount = Math.min(this.comboCount + 1, MAX_COMBO);
                    this.comboTimer = COMBO_WINDOW;

                    const damage = 15 + this.comboCount * 3;
                    const range = this.comboCount >= 3 ? 70 : 55;

                    this.attackHitbox = {
                        x: this.x + this.facing * 25 - 10,
                        y: this.y - 80,
                        w: range,
                        h: 60,
                    };

                    spawnSlash(this.x + this.facing * 40, this.y - 40, this.facing);
                    spawnParticles(this.x + this.facing * 40, this.y - 40, 5, "#ffd700", 3, 3, "spark");
                }

                heavyAttack() {
                    if (this.state !== "idle" && this.state !== "run") return;
                    if (this.stamina < 30) return;

                    this.stamina -= 30;
                    this.staminaRegenTimer = STAMINA_REGEN_DELAY + 10;
                    this.state = "heavy_attack";
                    this.stateTimer = 35;
                    this.comboCount = 0;

                    const damage = 40 + this.comboCount * 5;
                    this.attackHitbox = {
                        x: this.x + this.facing * 30 - 15,
                        y: this.y - 90,
                        w: 80,
                        h: 70,
                    };

                    setTimeout(() => {
                        spawnParticles(this.x + this.facing * 50, this.y - 40, 15, "#ff6b00", 6, 5, "circle");
                        spawnSlash(this.x + this.facing * 50, this.y - 40, this.facing);

                        for (const enemy of enemies) {
                            const dist = Math.hypot(enemy.x - (this.x + this.facing * 50), (enemy.y - 40) - (this.y - 40));
                            if (dist < 90) {
                                enemy.takeDamage(damage, this.facing);
                                enemy.knockback(this.facing * 6);
                            }
                        }
                    }, 15);
                }

                dodge() {
                    if (this.dodgeCooldownTimer > 0) return;
                    if (this.stamina < 20) return;

                    this.stamina -= 20;
                    this.staminaRegenTimer = STAMINA_REGEN_DELAY;
                    this.state = "dodge";
                    this.dodgeTimer = DODGE_DURATION;
                    this.dodgeCooldownTimer = DODGE_COOLDOWN;
                    this.iFrames = DODGE_DURATION;
                    this.vx = this.facing * DODGE_SPEED;
                    this.comboCount = 0;

                    spawnParticles(this.x, this.y - 30, 8, "#aaaaaa", 4, 3);
                }

                useSkill(index) {
                    if (index < 0 || index >= SKILLS.length) return;
                    const skill = SKILLS[index];
                    if (skill.currentCooldown > 0 || this.mana < skill.manaCost) return;

                    this.mana -= skill.manaCost;
                    skill.currentCooldown = skill.cooldown;
                    this.state = "skill";
                    this.stateTimer = 25;

                    skill.execute(this, enemies, particles);
                    spawnParticles(this.x, this.y - 40, 15, skill.color, 5, 4, "circle");
                }

                takeDamage(amount) {
                    if (this.iFrames > 0) return;
                    this.hp -= amount;
                    this.iFrames = 20;
                    this.state = "hurt";
                    this.stateTimer = 15;
                    screenShake = 8;
                    spawnParticles(this.x, this.y - 40, 10, "#ff0000", 5, 4);

                    if (this.hp <= 0) {
                        this.hp = 0;
                        return true;
                    }
                    return false;
                }

                update(dt, keys) {
                    // Timers
                    if (this.stateTimer > 0) this.stateTimer -= dt;
                    if (this.dodgeTimer > 0) this.dodgeTimer -= dt;
                    if (this.dodgeCooldownTimer > 0) this.dodgeCooldownTimer -= dt;
                    if (this.comboTimer > 0) {
                        this.comboTimer -= dt;
                        if (this.comboTimer <= 0) this.comboCount = 0;
                    }
                    if (this.iFrames > 0) this.iFrames -= dt;

                    // Stamina regen
                    if (this.staminaRegenTimer > 0) {
                        this.staminaRegenTimer -= dt;
                    } else {
                        this.stamina = Math.min(this.maxStamina, this.stamina + STAMINA_REGEN * dt);
                    }

                    // Mana regen
                    this.mana = Math.min(this.maxMana, this.mana + MANA_REGEN * dt);

                    // Skill cooldowns
                    for (const skill of SKILLS) {
                        if (skill.currentCooldown > 0) skill.currentCooldown -= dt;
                    }

                    // State transitions
                    if (this.stateTimer <= 0) {
                        if (this.state === "combo" || this.state === "heavy_attack" || this.state === "skill" || this.state === "hurt") {
                            this.state = "idle";
                        }
                        if (this.dodgeTimer <= 0 && this.state === "dodge") {
                            this.state = "idle";
                        }
                    }

                    // Movement
                    if (this.state === "idle" || this.state === "run" || this.state === "combo") {
                        let moveX = 0;
                        if (keys["a"] || keys["arrowleft"]) moveX -= 1;
                        if (keys["d"] || keys["arrowright"]) moveX += 1;

                        const sprinting = keys["shift"] && this.stamina > 0 && moveX !== 0;
                        const speed = PLAYER_SPEED * (sprinting ? SPRINT_MULTIPLIER : 1);

                        if (sprinting) {
                            this.stamina -= 0.3 * dt;
                            if (Math.random() > 0.7) {
                                spawnParticles(this.x, this.y, 1, "#aaaaaa", 1, 2);
                            }
                        }

                        this.vx = moveX * speed;
                        if (moveX !== 0) {
                            this.facing = moveX;
                            this.state = "run";
                        } else if (this.state === "run") {
                            this.state = "idle";
                        }

                        // Jump
                        if ((keys["w"] || keys["arrowup"] || keys[" "]) && this.grounded) {
                            this.vy = JUMP_FORCE;
                            this.grounded = false;
                        }
                    } else if (this.state === "dodge") {
                        this.vx *= 0.85;
                    } else {
                        this.vx = 0;
                    }

                    // Gravity
                    if (!this.grounded) {
                        this.vy += GRAVITY * dt;
                    }

                    this.x += this.vx * dt;
                    this.y += this.vy * dt;

                    // Ground
                    if (this.y >= H - 100) {
                        this.y = H - 100;
                        this.vy = 0;
                        this.grounded = true;
                    }

                    this.x = Math.max(30, Math.min(W - 30, this.x));

                    // Animation
                    this.animTimer += dt;
                    if (this.animTimer > 6) {
                        this.animTimer = 0;
                        this.animFrame = (this.animFrame + 1) % 4;
                    }

                    // Reset attack hitbox
                    if (this.state !== "combo" && this.state !== "heavy_attack") {
                        this.attackHitbox = null;
                    }
                }

                draw(ctx) {
                    ctx.save();
                    ctx.translate(this.x, this.y);

                    const flash = this.iFrames > 0 && Math.floor(this.iFrames) % 2 === 0;
                    if (this.state === "dodge") {
                        ctx.globalAlpha = 0.6;
                    }

                    const dir = this.facing;
                    const bobY = this.state === "run" ? Math.sin(this.animFrame * Math.PI / 2) * 4 : 0;

                    // Shadow
                    ctx.fillStyle = "rgba(0,0,0,0.3)";
                    ctx.beginPath();
                    ctx.ellipse(0, 5, 20, 6, 0, 0, Math.PI * 2);
                    ctx.fill();

                    // Body
                    ctx.fillStyle = flash ? "#ffffff" : "#d4a017";
                    ctx.beginPath();
                    ctx.roundRect(-15, -70 + bobY, 30, 45, 5);
                    ctx.fill();

                    // Armor details
                    ctx.fillStyle = "#b8860b";
                    ctx.fillRect(-17, -65 + bobY, 4, 35);
                    ctx.fillRect(13, -65 + bobY, 4, 35);

                    // Belt
                    ctx.fillStyle = "#8b4513";
                    ctx.fillRect(-16, -30 + bobY, 32, 6);

                    // Legs
                    ctx.fillStyle = "#8b4513";
                    if (this.state === "run") {
                        const legPhase = Math.sin(this.animFrame * Math.PI / 2);
                        ctx.fillRect(-12, -25 + bobY, 10, 25);
                        ctx.fillRect(2, -25 - legPhase * 5 + bobY, 10, 25);
                    } else if (this.state === "dodge") {
                        ctx.fillRect(-14, -25 + bobY, 12, 25);
                        ctx.fillRect(2, -25 + bobY, 12, 25);
                    } else {
                        ctx.fillRect(-12, -25 + bobY, 10, 25);
                        ctx.fillRect(2, -25 + bobY, 10, 25);
                    }

                    // Arms
                    ctx.fillStyle = "#d4a017";
                    if (this.state === "combo") {
                        ctx.save();
                        ctx.translate(dir * 18, -55 + bobY);
                        ctx.rotate(dir * (0.5 + Math.sin(this.stateTimer * 0.3) * 1.5));
                        ctx.fillRect(-5, 0, 10, 30);
                        // Staff
                        ctx.fillStyle = "#ffd700";
                        ctx.fillRect(-3, -35, 6, 70);
                        ctx.fillStyle = "#ff4400";
                        ctx.beginPath();
                        ctx.arc(0, -35, 6, 0, Math.PI * 2);
                        ctx.fill();
                        ctx.restore();
                    } else if (this.state === "heavy_attack") {
                        ctx.save();
                        ctx.translate(dir * 20, -55 + bobY);
                        ctx.rotate(dir * (-0.5 + (35 - this.stateTimer) / 35 * 2));
                        ctx.fillRect(-5, 0, 10, 30);
                        ctx.fillStyle = "#ffd700";
                        ctx.fillRect(-3, -45, 6, 80);
                        ctx.restore();
                    } else {
                        const armPhase = this.state === "run" ? Math.sin(this.animFrame * Math.PI / 2) * 8 : 0;
                        ctx.fillRect(dir * 15, -60 + armPhase + bobY, 10, 25);

                        // Staff (idle)
                        ctx.fillStyle = "#ffd700";
                        ctx.fillRect(dir * 20, -80 + bobY, 5, 60);
                        ctx.fillStyle = "#ff4400";
                        ctx.beginPath();
                        ctx.arc(dir * 22, -80 + bobY, 5, 0, Math.PI * 2);
                        ctx.fill();
                    }

                    // Head
                    ctx.fillStyle = flash ? "#ffffff" : "#ffcc66";
                    ctx.beginPath();
                    ctx.arc(0, -78 + bobY, 14, 0, Math.PI * 2);
                    ctx.fill();

                    // Headband
                    ctx.fillStyle = "#ff0000";
                    ctx.fillRect(-15, -85 + bobY, 30, 5);
                    ctx.fillRect(dir * 12, -88 + bobY, 12, 4);

                    // Eyes
                    ctx.fillStyle = "#ff4400";
                    ctx.beginPath();
                    ctx.arc(dir * 4, -78 + bobY, 3, 0, Math.PI * 2);
                    ctx.arc(dir * 10, -78 + bobY, 2.5, 0, Math.PI * 2);
                    ctx.fill();

                    // Golden circlet
                    ctx.strokeStyle = "#ffd700";
                    ctx.lineWidth = 2;
                    ctx.beginPath();
                    ctx.arc(0, -78 + bobY, 16, -0.8, 0.8);
                    ctx.stroke();

                    ctx.restore();
                }
            }

            // ============================================
            // GAME STATE
            // ============================================
            let gameState = "MENU";
            let player;
            let enemies = [];
            let particles = [];
            let damageNumbers = [];
            let screenShake = 0;
            let keys = {};
            let waveNumber = 0;
            let waveTimer = 0;
            let bossSpawned = false;
            let cameraX = 0;
            let bgOffset = 0;

            // ============================================
            // WAVE SYSTEM
            // ============================================
            function spawnWave() {
                waveNumber++;

                if (waveNumber % 5 === 0 && !bossSpawned) {
                    // Boss wave
                    const boss = new Enemy(W - 150, H - 100, "boss");
                    enemies.push(boss);
                    bossSpawned = true;
                    bossHealthContainer.style.display = "block";
                    bossNameDisplay.textContent = "🐉 DEMON KING — Phase " + (Math.floor(waveNumber / 5));
                    spawnParticles(W - 150, H - 150, 40, "#ff0000", 10, 6, "circle");
                } else {
                    const count = Math.min(2 + Math.floor(waveNumber / 2), 6);
                    for (let i = 0; i < count; i++) {
                        const side = Math.random() > 0.5 ? W - 80 : 80;
                        const type = Math.random() > 0.7 ? "heavy" : "minion";
                        enemies.push(new Enemy(side + (Math.random() - 0.5) * 100, H - 100, type));
                    }
                }
            }

            function resetGame() {
                player = new Player();
                enemies = [];
                particles = [];
                damageNumbers = [];
                screenShake = 0;
                waveNumber = 0;
                waveTimer = 0;
                bossSpawned = false;
                bossHealthContainer.style.display = "none";
                cameraX = 0;
                gameState = "PLAYING";
                spawnWave();
            }

            // ============================================
            // UPDATE
            // ============================================
            function update(dt) {
                if (gameState !== "PLAYING") return;

                player.update(dt, keys);

                // Combo display
                if (player.comboCount > 1) {
                    comboDisplay.textContent = player.comboCount + " HIT!";
                    comboDisplay.style.opacity = "1";
                } else {
                    comboDisplay.style.opacity = "0";
                }

                // Update enemies
                for (let i = enemies.length - 1; i >= 0; i--) {
                    const enemy = enemies[i];
                    enemy.update(dt, player.x, player.y);

                    // Player attacks enemy
                    if (player.state === "combo" && player.stateTimer === 15) {
                        const hitbox = player.getAttackHitbox();
                        const enemyBox = { x: enemy.x - enemy.size / 2, y: enemy.y - enemy.size, w: enemy.size, h: enemy.size };
                        if (checkCollision(hitbox, enemyBox)) {
                            const damage = 15 + player.comboCount * 3;
                            enemy.takeDamage(damage, player.facing);
                            enemy.knockback(player.facing * 4);
                            spawnParticles(enemy.x, enemy.y - enemy.size / 2, 8, "#ffd700", 4, 3, "spark");
                        }
                    }

                    // Enemy attacks player
                    if (enemy.state === "attack" && enemy.stateTimer === 25) {
                        const enemyHitbox = enemy.getAttackHitbox();
                        const playerBox = { x: player.x - 15, y: player.y - 80, w: 30, h: 80 };
                        if (checkCollision(enemyHitbox, playerBox)) {
                            if (player.takeDamage(enemy.damage)) {
                                gameOver();
                                return;
                            }
                        }
                    }

                    // Remove dead enemies
                    if (enemy.hp <= 0) {
                        player.souls += enemy.souls;
                        player.kills++;
                        spawnParticles(enemy.x, enemy.y - enemy.size / 2, 20, "#ffd700", 8, 4);
                        spawnParticles(enemy.x, enemy.y - enemy.size / 2, 10, "#ff4400", 6, 3);

                        if (enemy.type === "boss") {
                            bossSpawned = false;
                            bossHealthContainer.style.display = "none";
                            victory();
                            return;
                        }

                        enemies.splice(i, 1);
                    }
                }

                // Boss health bar
                if (bossSpawned) {
                    const boss = enemies.find(e => e.type === "boss");
                    if (boss) {
                        bossHealthFill.style.width = (boss.hp / boss.maxHp * 100) + "%";
                    }
                }

                // Particles
                for (let i = particles.length - 1; i >= 0; i--) {
                    particles[i].update(dt);
                    if (particles[i].life <= 0) particles.splice(i, 1);
                }

                // Damage numbers
                for (let i = damageNumbers.length - 1; i >= 0; i--) {
                    damageNumbers[i].update(dt);
                    if (damageNumbers[i].life <= 0) damageNumbers.splice(i, 1);
                }

                // Wave spawning
                waveTimer += dt;
                if (enemies.length === 0 && waveTimer > 60) {
                    spawnWave();
                    waveTimer = 0;
                }

                // Screen shake
                if (screenShake > 0) screenShake -= dt;

                // Update HUD
                healthBar.style.width = (player.hp / player.maxHp * 100) + "%";
                staminaBar.style.width = (player.stamina / player.maxStamina * 100) + "%";
                manaBar.style.width = (player.mana / player.maxMana * 100) + "%";
                healthValue.textContent = Math.floor(player.hp) + "/" + player.maxHp;
                staminaValue.textContent = Math.floor(player.stamina) + "/" + player.maxStamina;
                manaValue.textContent = Math.floor(player.mana) + "/" + player.maxMana;
                soulsDisplay.textContent = player.souls;
                killsDisplay.textContent = player.kills;
                comboCountDisplay.textContent = player.comboCount;

                // Update skill cooldowns
                for (let i = 0; i < SKILLS.length; i++) {
                    const slot = document.getElementById("skill" + i);
                    const skill = SKILLS[i];
                    if (skill.currentCooldown > 0) {
                        slot.classList.add("on-cooldown");
                        let overlay = slot.querySelector(".skill-cooldown-overlay");
                        if (!overlay) {
                            overlay = document.createElement("div");
                            overlay.className = "skill-cooldown-overlay";
                            slot.appendChild(overlay);
                        }
                        overlay.style.height = "100%";
                        overlay.textContent = Math.ceil(skill.currentCooldown / 60);
                    } else {
                        slot.classList.remove("on-cooldown");
                        const overlay = slot.querySelector(".skill-cooldown-overlay");
                        if (overlay) overlay.remove();
                    }
                }

                // Background scroll
                bgOffset += player.vx * 0.3 * dt;
            }

            function checkCollision(a, b) {
                return a.x < b.x + b.w && a.x + a.w > b.x && a.y < b.y + b.h && a.y + a.h > b.y;
            }

            function gameOver() {
                gameState = "GAMEOVER";
                finalStats.innerHTML =
                    `🪙 Souls Collected: <span>${player.souls}</span><br>` +
                    `⚔️ Enemies Defeated: <span>${player.kills}</span><br>` +
                    `🌊 Waves Survived: <span>${waveNumber}</span>`;
                setTimeout(() => { gameOverScreen.style.display = "flex"; }, 800);
            }

            function victory() {
                gameState = "VICTORY";
                victoryStats.innerHTML =
                    `🪙 Souls Collected: <span>${player.souls}</span><br>` +
                    `⚔️ Enemies Defeated: <span>${player.kills}</span><br>` +
                    `🌊 Waves Cleared: <span>${waveNumber}</span>`;
                setTimeout(() => { victoryScreen.style.display = "flex"; }, 800);
            }

            // ============================================
            // RENDERING
            // ============================================
            function drawBackground() {
                // Sky gradient
                const skyGrad = ctx.createLinearGradient(0, 0, 0, H);
                skyGrad.addColorStop(0, "#0a0a1a");
                skyGrad.addColorStop(0.3, "#1a0a2a");
                skyGrad.addColorStop(0.7, "#2a1a1a");
                skyGrad.addColorStop(1, "#1a1a0a");
                ctx.fillStyle = skyGrad;
                ctx.fillRect(0, 0, W, H);

                // Moon
                ctx.fillStyle = "#ffffcc";
                ctx.shadowColor = "#ffffcc";
                ctx.shadowBlur = 40;
                ctx.beginPath();
                ctx.arc(700, 80, 40, 0, Math.PI * 2);
                ctx.fill();
                ctx.shadowBlur = 0;

                // Stars
                ctx.fillStyle = "rgba(255,255,255,0.5)";
                for (let i = 0; i < 50; i++) {
                    const sx = (i * 97 + bgOffset * 0.02) % W;
                    const sy = (i * 53) % (H * 0.5);
                    ctx.beginPath();
                    ctx.arc(sx, sy, 1 + (i % 2), 0, Math.PI * 2);
                    ctx.fill();
                }

                // Mountains (parallax)
                ctx.fillStyle = "#1a0a2a";
                ctx.beginPath();
                ctx.moveTo(0, H * 0.5);
                for (let x = 0; x <= W; x += 50) {
                    const mx = x + bgOffset * 0.1;
                    const my = H * 0.5 - Math.sin(mx * 0.005) * 80 - Math.sin(mx * 0.01) * 40;
                    ctx.lineTo(x, my);
                }
                ctx.lineTo(W, H);
                ctx.lineTo(0, H);
                ctx.closePath();
                ctx.fill();

                // Closer mountains
                ctx.fillStyle = "#2a1a1a";
                ctx.beginPath();
                ctx.moveTo(0, H * 0.6);
                for (let x = 0; x <= W; x += 30) {
                    const mx = x + bgOffset * 0.2;
                    const my = H * 0.6 - Math.sin(mx * 0.008) * 60 - Math.cos(mx * 0.015) * 30;
                    ctx.lineTo(x, my);
                }
                ctx.lineTo(W, H);
                ctx.lineTo(0, H);
                ctx.closePath();
                ctx.fill();

                // Ground
                const groundGrad = ctx.createLinearGradient(0, H - 100, 0, H);
                groundGrad.addColorStop(0, "#2a1a0a");
                groundGrad.addColorStop(1, "#1a0a00");
                ctx.fillStyle = groundGrad;
                ctx.fillRect(0, H - 100, W, 100);

                // Ground texture
                ctx.strokeStyle = "rgba(100,70,30,0.3)";
                ctx.lineWidth = 1;
                for (let x = 0; x < W; x += 20) {
                    const gx = (x - bgOffset * 0.5) % W;
                    ctx.beginPath();
                    ctx.moveTo(gx < 0 ? gx + W : gx, H - 100);
                    ctx.lineTo(gx < 0 ? gx + W : gx, H);
                    ctx.stroke();
                }

                // Fog
                ctx.fillStyle = "rgba(100,80,60,0.08)";
                for (let i = 0; i < 5; i++) {
                    const fx = ((i * 200 + bgOffset * 0.3 + Date.now() * 0.02) % (W + 200)) - 100;
                    const fy = H - 120 + Math.sin(Date.now() * 0.001 + i) * 10;
                    ctx.beginPath();
                    ctx.ellipse(fx, fy, 150, 30, 0, 0, Math.PI * 2);
                    ctx.fill();
                }
            }

            function render() {
                ctx.save();

                if (screenShake > 0) {
                    ctx.translate(
                        (Math.random() - 0.5) * screenShake,
                        (Math.random() - 0.5) * screenShake
                    );
                }

                ctx.clearRect(0, 0, W, H);
                drawBackground();

                // Draw enemies (sorted by y)
                const sortedEnemies = [...enemies].sort((a, b) => a.y - b.y);
                for (const enemy of sortedEnemies) {
                    enemy.draw(ctx);
                }

                // Draw player
                player.draw(ctx);

                // Draw particles
                for (const p of particles) {
                    p.draw(ctx);
                }

                // Draw damage numbers
                for (const dn of damageNumbers) {
                    dn.draw(ctx);
                }

                ctx.restore();
            }

            // ============================================
            // GAME LOOP
            // ============================================
            let lastTime = 0;
            let accumulator = 0;

            function gameLoop(timestamp) {
                if (!lastTime) lastTime = timestamp;
                const frameTime = Math.min((timestamp - lastTime) / 16.67, 3);
                lastTime = timestamp;
                accumulator += frameTime;

                while (accumulator >= 1) {
                    update(1);
                    accumulator -= 1;
                }

                render();
                requestAnimationFrame(gameLoop);
            }

            // ============================================
            // INPUT
            // ============================================
            document.addEventListener("keydown", (e) => {
                const key = e.key.toLowerCase();
                keys[key] = true;

                if (gameState !== "PLAYING") return;

                if (key === "j") player.lightAttack();
                if (key === "k") player.heavyAttack();
                if (key === "l") player.dodge();
                if (key === "u") player.useSkill(0);
                if (key === "i") player.useSkill(1);
                if (key === "o") player.useSkill(2);

                // Prevent scrolling
                if (["arrowup", "arrowdown", "arrowleft", "arrowright", " "].includes(key)) {
                    e.preventDefault();
                }
            });

            document.addEventListener("keyup", (e) => {
                keys[e.key.toLowerCase()] = false;
            });

            // ============================================
            // BUTTONS
            // ============================================
            startBtn.addEventListener("click", () => {
                startScreen.style.display = "none";
                resetGame();
            });

            retryBtn.addEventListener("click", () => {
                gameOverScreen.style.display = "none";
                resetGame();
            });

            victoryBtn.addEventListener("click", () => {
                victoryScreen.style.display = "none";
                resetGame();
            });

            // ============================================
            // START
            // ============================================
            resetGame();
            requestAnimationFrame(gameLoop);
        })();
    </script>
</body>
</html>
